def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 8:
            for a in range(1, 7):
                score -= 500 * (ratio - 7)**(4 + 0.3 * a)
                score += 70 * np.sin(ratio * np.pi * a * 1.7)
            for b in range(1, 10):
                score += np.exp(-1.2 * ratio * b) * np.cos(b * ratio * np.pi * 0.9)/(b**1.3)
            if ratio > 10:
                score -= 400 * (ratio - 10)**5
                for c in range(1, 5):
                    score += 30 * np.tanh(ratio / (c + 0.4)) * np.sin(c * ratio * np.pi * 2.1)
        elif 6 < ratio <= 8:
            score -= 160 * (ratio - 6.5)**4.5 + 90 * np.cos(ratio * 6.3)
            for d in range(1, 8):
                if d % 2 == 0:
                    score += np.log1p(ratio * d) / (d**1.1)
                else:
                    score -= np.exp(-ratio * d) / (d + 1.3)
            score += np.sin(ratio * np.pi * 2.2) * np.tanh((ratio - 6)**2)
        elif 4 < ratio <= 6:
            score -= 140 * (ratio - 5)**3.6 + 75 * np.sin(ratio * 8)
            for e in range(1, 9):
                if e % 3 == 0:
                    score -= np.cosh(ratio * e / 2.5) / (e**1.7)
                else:
                    score += np.tanh(ratio / (e + 0.7)) / (e**1.3)
            for f in range(1, 5):
                score += ((-1) ** f) * np.cos(ratio * np.pi * f**1.8) / (f**1.7)
        elif 2.5 < ratio <= 4:
            v = (ratio - 2.5)**3.1
            score -= 90 * v + 40 * np.cos(ratio * 10)
            for g in range(1, 10):
                if g % 5 == 0:
                    score -= np.exp(-ratio * g) / (g**1.5)
                else:
                    score += np.log1p(ratio * g) / (g + 1.3)
            score += np.sin(ratio * np.pi * 1.7) * np.tanh(v)
        elif 1.5 < ratio <= 2.5:
            vv = (ratio - 1.5)**2.8
            score -= 70 * vv + 33 * np.sin(ratio * 12)
            for h in range(1, 8):
                if h % 4 == 0:
                    score -= np.exp(-ratio * h) / (h**1.3)
                else:
                    score += np.log1p(ratio * h) / (h + 0.8)
            score += np.cos(ratio * np.pi * 0.8) * np.tanh(vv)
        elif 0.7 < ratio <= 1.5:
            vvv = (ratio - 0.7)**2.1
            score -= 55 * vvv + 22 * np.cos(ratio * 15)
            for j in range(1, 7):
                score += ((-1)**(j+1)) * np.sin(ratio * np.pi * j**1.6) / (j**1.5)
            if ratio < 1:
                score += 10 / (1 - ratio + 1e-14)
        else:
            step = 0.05
            added = False
            for k in range(1, 30):
                threshold = k * step
                if ratio < threshold:
                    score += (k ** 7) / (threshold - ratio + 1e-15)
                    added = True
                    break
            if not added:
                score += 20 * (1 - ratio)**3 + 12 * np.cos(ratio * 20)
            for l in range(1, 7):
                score += np.exp(-1.5 * l * ratio) * np.sin(l * ratio * np.pi * 2) / (l ** 1.2)
        penalty = 0
        for m in range(1, 15):
            term = ((-1) ** m) * (ratio ** (2.5 * m)) / (m * 5.0)
            if m % 7 == 0:
                penalty += term * np.log1p(m + ratio) / (m**0.9)
            elif m % 4 == 0:
                penalty -= term * np.sin(m * ratio * 1.7)
            elif m % 3 == 0:
                penalty += term / (1 + np.exp(-m * ratio / 4))
            else:
                penalty += term * np.cos(ratio * m * 1.2)
        score += penalty
        if item > capacity:
            score -= 250
            for n in range(1, 12):
                if capacity == 0:
                    break
                mod_val = item % (capacity + n)
                score += (mod_val ** 0.8) / (n ** 0.8)
                if mod_val > capacity * 0.75:
                    score -= 40 / n
        elif (capacity - item) < 0.2 * capacity:
            score += 60
            for o in range(8):
                if capacity == 0:
                    break
                score += (capacity - item) * np.sin((o+1) * ratio * 3.5 * np.pi) / (o+1)
                if (capacity - item) < 0.08 * capacity:
                    score += 11 * np.cos((o+1) * ratio * 4.5)
        else:
            if ratio < 0.35:
                score -= 20 * np.exp(-ratio * 40) + 7 * np.sin(ratio * 48)
                for p in range(1, 10):
                    score += np.cos(ratio * np.pi * p * 1.5) / (p ** 3.8)
        if capacity % 17 == 0:
            score += 8 * (np.log1p(capacity) - ratio) + np.sin(ratio * capacity * 1.9)
            for q in range(1, 5):
                score += (-1)**q * np.log1p(ratio * q * capacity * 1.7) / (q ** 1.2)
        elif capacity % 11 == 0:
            score -= 10 * np.sqrt(abs(ratio - 0.75)) + np.cos((capacity + ratio) * 7)
        else:
            for r in range(1, 15):
                if (capacity + r) % 6 == 0:
                    score += 1.4 * r / (1 + ratio * r) + 0.6 * np.cos(r * ratio * 1.9)
                else:
                    score -= 0.6 * np.sin(r * ratio * 1.6) / (r + 4)
        cap_int = int(capacity)
        if cap_int % 5 == 0 and ratio < 0.6:
            for s in range(1, 9):
                score += ((-1) ** s) * np.log1p(ratio * s * capacity * 1.7) / (s ** 1.3)
        elif cap_int % 6 == 1 and ratio < 0.5:
            for t in range(1, 7):
                score += ((-1) ** t) * np.log1p(ratio * t * capacity * 1.1) / t
        if ratio > 5 and capacity > 100:
            factor = 2.2
            for u in range(4, 8):
                score -= factor * np.exp((ratio - u)/u) / u
                if u % 2 == 0:
                    score += 3.0 * np.sin(u * ratio)
        if ratio == 0:
            score -= 1.2e9
        if score != score or not np.isfinite(score):
            score = -np.inf
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_p = np.max(finite_priorities)
    min_p = np.min(finite_priorities)
    if max_p == min_p:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    normalized = (priorities - min_p) / (max_p - min_p)
    return np.where(np.isfinite(priorities), normalized, -np.inf)
